theme.custom_css_code:
.fp-chart-card {
  padding: 20px;
  border-radius: 22px;
  background: linear-gradient(180deg, rgba(61, 38, 27, 0.86) 0%, rgba(34, 22, 17, 0.92) 100%);
  border: 1px solid rgba(204, 156, 112, 0.22);
  box-shadow: 0 16px 38px rgba(0, 0, 0, 0.24);
  font-family: Arial, sans-serif;
}

.fp-chart-row {
  display: grid;
  grid-template-columns: 180px minmax(0, 1fr) 72px;
  align-items: center;
  gap: 14px;
  margin-bottom: 14px;
}

.fp-chart-row:last-child {
  margin-bottom: 0;
}

.fp-chart-label {
  font-size: 14px;
  line-height: 1.35;
  color: #ffe0c1;
  font-weight: 700;
}

.fp-chart-bar {
  position: relative;
  height: 14px;
  border-radius: 999px;
  background: rgba(255, 234, 214, 0.1);
  overflow: hidden;
}

.fp-chart-fill {
  display: block;
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, #d79b64 0%, #ffcf9b 100%);
  box-shadow: 0 0 18px rgba(255, 202, 149, 0.25);
}

.fp-chart-value {
  text-align: right;
  font-size: 13px;
  font-weight: 700;
  color: #f5eee8;
}

@media (max-width: 767px) {
  .fp-chart-card {
    padding: 16px;
  }

  .fp-chart-row {
    grid-template-columns: 1fr;
    gap: 8px;
    margin-bottom: 16px;
  }

  .fp-chart-value {
    text-align: left;
  }
}
.fp-games-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 16px;
  background: transparent;
}

.fp-game-card {
  position: relative;
  min-height: 190px;
  padding: 18px;
  border-radius: 20px;
  background:
    linear-gradient(180deg, rgba(255, 218, 182, 0.1) 0%, rgba(71, 44, 30, 0.88) 100%);
  border: 1px solid rgba(205, 157, 110, 0.24);
  box-shadow: 0 14px 34px rgba(0, 0, 0, 0.22);
  font-family: Arial, sans-serif;
  overflow: hidden;
}

.fp-game-card::before {
  content: "";
  position: absolute;
  inset: 0;
  background:
    radial-gradient(circle at top right, rgba(255, 213, 170, 0.12), transparent 36%),
    radial-gradient(circle at bottom left, rgba(255, 178, 102, 0.08), transparent 40%);
  pointer-events: none;
}

.fp-game-icon {
  position: relative;
  z-index: 1;
  width: 54px;
  height: 54px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 14px;
  border-radius: 16px;
  font-size: 26px;
  background: rgba(255, 226, 196, 0.1);
  border: 1px solid rgba(255, 214, 170, 0.18);
}

.fp-game-name {
  position: relative;
  z-index: 1;
  margin-bottom: 10px;
  font: 700 18px/1.25 Arial, sans-serif;
  color: #ffe0bf;
}

.fp-game-text {
  position: relative;
  z-index: 1;
  font: 400 14px/1.55 Arial, sans-serif;
  color: #f4ebe4;
}

@media (max-width: 991px) {
  .fp-games-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 575px) {
  .fp-games-grid {
    grid-template-columns: 1fr;
  }

  .fp-game-card {
    min-height: auto;
    padding: 16px;
  }
}
.fp-brand-table-wrap {
  width: 100%;
  overflow-x: auto;
  background: transparent;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: thin;
  scrollbar-color: #8f6a4b #2a1b14;
}

.fp-brand-table-wrap::-webkit-scrollbar {
  height: 10px;
}

.fp-brand-table-wrap::-webkit-scrollbar-track {
  background: #2a1b14;
  border-radius: 999px;
}

.fp-brand-table-wrap::-webkit-scrollbar-thumb {
  background: #8f6a4b;
  border-radius: 999px;
}

.fp-brand-table {
  width: 100%;
  min-width: 720px;
  border-collapse: collapse;
  font-family: Arial, sans-serif;
  color: #f7efe9;
  background: rgba(52, 33, 24, 0.72);
  border: 1px solid rgba(201, 157, 116, 0.28);
  border-radius: 18px;
  overflow: hidden;
}

.fp-brand-table td {
  padding: 14px 16px;
  font-size: 15px;
  line-height: 1.5;
  border-bottom: 1px solid rgba(201, 157, 116, 0.16);
  vertical-align: top;
}

.fp-brand-table tr:last-child td {
  border-bottom: none;
}

.fp-brand-table td:first-child {
  width: 32%;
  font-weight: 700;
  color: #ffd9b3;
  background: rgba(255, 214, 176, 0.05);
}

.fp-brand-table td:last-child {
  color: #f7efe9;
}

@media (max-width: 767px) {
  .fp-brand-table td {
    padding: 12px 14px;
    font-size: 14px;
  }
}
